                  </p>
                  <div className="text-right text-magic-black/40 dark:text-off-white/40 font-archivo text-[10px] uppercase tracking-widest">
                    {selectedProject.category[lang]} — EST. 2024
                  </div>
                </div>
              </div>

              <div className="space-y-12">
                {selectedProject.gallery.map((img, i) => (
                  <img key={i} src={img} alt="" className="w-full h-auto object-cover rounded-sm shadow-sm" />
                ))}
