import React, { useState, useEffect, useRef } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import ProjectsGrid from './components/ProjectsGrid';
import Section from './components/Section';
import { Language, Project } from './types';
import { TRANSLATIONS } from './constants';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('de');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [mousePos, setMousePos] = useState({ x: -500, y: -500 });
  const [blob1Pos, setBlob1Pos] = useState({ x: 0, y: 0 });
  const [blob2Pos, setBlob2Pos] = useState({ x: 0, y: 0 });
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const requestRef = useRef<number>(null);

  const [headerTheme, setHeaderTheme] = useState({
    bg: 'bg-transparent',
    text: 'text-magic-black dark:text-off-white',
    shadow: '',
    blobColor: 'bg-magic-orange'
  });

  const t = TRANSLATIONS[lang] || TRANSLATIONS.de;

  // Mouse & Touch Tracking
  useEffect(() => {
    const handleMove = (e: MouseEvent | TouchEvent) => {
      const x = 'touches' in e ? e.touches[0].clientX : e.clientX;
      const y = 'touches' in e ? e.touches[0].clientY : e.clientY;
      setMousePos({ x, y });
    };

    window.addEventListener('mousemove', handleMove);
    window.addEventListener('touchmove', handleMove, { passive: true });

    if (mousePos.x === -500) {
      setMousePos({ x: window.innerWidth / 2, y: window.innerHeight / 2 });
    }

    return () => {
      window.removeEventListener('mousemove', handleMove);
      window.removeEventListener('touchmove', handleMove);
    };
  }, [mousePos.x]);

  // Smooth Follow Animation for Blobs
  useEffect(() => {
    let time = 0;
    const animate = () => {
      time += 0.01;
      const driftX = Math.sin(time * 0.5) * 20;
      const driftY = Math.cos(time * 0.3) * 20;

      setBlob1Pos((prev) => ({
        x: prev.x + (mousePos.x + driftX - prev.x) * 0.06,
        y: prev.y + (mousePos.y + driftY - prev.y) * 0.06,
      }));
      setBlob2Pos((prev) => ({
        x: prev.x + (mousePos.x - driftX - prev.x) * 0.03,
        y: prev.y + (mousePos.y - driftY - prev.y) * 0.03,
      }));
      requestRef.current = requestAnimationFrame(animate);
    };
    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [mousePos]);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const handleScroll = () => {
      const scrollPos = window.scrollY + 120;
      const services = document.getElementById('services');
      const projects = document.getElementById('projects');
      const about = document.getElementById('about');
      const contact = document.getElementById('contact');

      if (contact && scrollPos >= contact.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-pink', 
          text: 'text-magic-black', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,183,213,0.6)]',
          blobColor: 'bg-magic-pink'
        });
      } else if (about && scrollPos >= about.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-blue', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(0,56,255,0.6)]',
          blobColor: 'bg-magic-blue'
        });
      } else if (services && scrollPos >= services.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-yellow-400', 
          text: 'text-magic-black', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(250,204,21,0.6)]',
          blobColor: 'bg-yellow-400'
        });
      } else if (projects && scrollPos >= projects.offsetTop) {
        setHeaderTheme({ 
          bg: 'bg-magic-orange', 
          text: 'text-white', 
          shadow: 'dark:shadow-[0_10px_40px_-10px_rgba(255,77,0,0.6)]',
          blobColor: 'bg-magic-orange'
        });
      } else {
        setHeaderTheme({ 
          bg: 'bg-transparent', 
          text: 'text-magic-black dark:text-off-white', 
          shadow: '',
          blobColor: 'bg-magic-orange'
        });
      }
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  return (
    <div className="relative overflow-hidden selection:bg-magic-orange selection:text-white bg-off-white dark:bg-magic-dark transition-colors duration-500 min-h-screen">

      {/* Dynamic Duo-Blob Background - Back to Graphic Roots */}
      <div className="pointer-events-none fixed inset-0 z-[5] overflow-hidden">
        <div 
          className={`absolute w-[100vw] h-[100vw] md:w-[60vw] md:h-[60vw] max-w-[900px] max-h-[900px] rounded-full blur-[80px] md:blur-[150px] opacity-70 md:opacity-80 dark:opacity-90 transition-colors duration-500 ease-in-out ${headerTheme.blobColor}`}
          style={{
            left: blob1Pos.x,
            top: blob1Pos.y,
            transform: 'translate(-50%, -50%)',
            willChange: 'left, top'
          }}
        />
        <div 
          className={`absolute w-[80vw] h-[80vw] md:w-[50vw] md:h-[50vw] max-w-[800px] max-h-[800px] rounded-full blur-[100px] md:blur-[180px] opacity-50 md:opacity-60 dark:opacity-70 transition-colors duration-500 ease-in-out ${headerTheme.blobColor}`}
          style={{
            left: blob2Pos.x,
            top: blob2Pos.y,
            transform: 'translate(-50%, -50%)',
            willChange: 'left, top'
          }}
        />
      </div>

      <Header 
        bgColor={`${headerTheme.bg} ${headerTheme.shadow}`} 
        textColor={headerTheme.text} 
        lang={lang} 
        setLang={setLang} 
        isDarkMode={isDarkMode}
        toggleDarkMode={toggleDarkMode}
        onNavClick={() => setSelectedProject(null)}
      />

      <main className="relative z-[10]">
        <Hero lang={lang} />

        <ProjectsGrid 
          lang={lang} 
          selectedProject={selectedProject} 
          setSelectedProject={setSelectedProject} 
        />

        <Section id="services" title={t.whatWeDo.title} subtitle={t.whatWeDo.subtitle} className="bg-transparent py-16 md:py-32">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 md:gap-12 mt-12">
            {t.whatWeDo.services.map((service, i) => (
              <div key={i} className="group pt-0 md:pt-4 transition-all duration-500">
